import{_ as e,c as t,a as r,o as n}from"./app-CEcM0piI.js";const s={};function i(p,a){return n(),t("div",null,a[0]||(a[0]=[r('<p>是一个静态类,用来操作文件路径的</p><h1 id="file" tabindex="-1"><a class="header-anchor" href="#file"><span>File</span></a></h1><p>静态类用于操作文件</p><h1 id="list" tabindex="-1"><a class="header-anchor" href="#list"><span>list</span></a></h1><p><strong>RemoveAll</strong> 传入的是一个回调函数也可以是匿名函数用于指定删除规则,该函数删除集合中所有符合条件的元素</p><p><strong>AddRange</strong> 传入的是集合类型,将指定集合中的所有元素添加到当前集合中</p><p><strong>InsertRange</strong> 插入指定集合中的所有元素</p><p><strong>ToArray</strong> 转换为数组</p><h1 id="dictionary" tabindex="-1"><a class="header-anchor" href="#dictionary"><span>Dictionary</span></a></h1><p>字典类型 存储的是KeyValuePair&lt;T,Y&gt;键值对类型通过Key属性获取key值,通过Value属性获取Value值</p><h1 id="filestream" tabindex="-1"><a class="header-anchor" href="#filestream"><span>FileStream</span></a></h1><p>由于FIle类型是一次性读取会对内存造成很大负荷</p><h1 id="md5" tabindex="-1"><a class="header-anchor" href="#md5"><span>MD5</span></a></h1><p>md5加密是不可逆的,如果是简单的内容可以解码出来,如果是复杂的就无法解码 c#中提供了MD5类用于md5加密和解密</p><h1 id="directory" tabindex="-1"><a class="header-anchor" href="#directory"><span>Directory</span></a></h1><p>用于操作目录</p>',16)]))}const c=e(s,[["render",i]]),d=JSON.parse('{"path":"/game/cs/3/","title":"3 常用工具类","lang":"zh-CN","frontmatter":{"title":"3 常用工具类","createTime":"2025/04/05 12:12:26","permalink":"/game/cs/3/"},"readingTime":{"minutes":0.82,"words":245},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/游戏/C#/3 常用工具类.md","headers":[]}');export{c as comp,d as data};
